15	/// Clear the cache, removing all entries or those linked to specific packages.
16	pub(crate) async fn cache_clean(
17	    packages: &[PackageName],
18	    force: bool,
19	    cache: Cache,
20	    printer: Printer,
21	) -> Result<ExitStatus> {
22	    if !cache.root().exists() {
23	        writeln!(
24	            printer.stderr(),
25	            "No cache found at: {}",
26	            cache.root().user_display().cyan()
27	        )?;
28	        return Ok(ExitStatus::Success);
29	    }
30	
31	    let cache = match cache.with_exclusive_lock_no_wait() {
32	        Ok(cache) => cache,
33	        Err(cache) if force => {
34	            debug!("Cache is currently in use, proceeding due to `--force`");
35	            cache
36	        }
37	        Err(cache) => {
38	            writeln!(
39	                printer.stderr(),
40	                "Cache is currently in-use, waiting for other uv processes to finish (use `--force` to override)"
41	            )?;
42	            cache.with_exclusive_lock().await?
43	        }
44	    };
45	
46	    let summary = if packages.is_empty() {
47	        writeln!(
48	            printer.stderr(),
49	            "Clearing cache at: {}",
50	            cache.root().user_display().cyan()
51	        )?;
52	
53	        let num_paths = walkdir::WalkDir::new(cache.root()).into_iter().count();
54	        let reporter = CleaningDirectoryReporter::new(printer, Some(num_paths));
55	
56	        let root = cache.root().to_path_buf();
57	        cache
58	            .clear(Box::new(reporter))
59	            .with_context(|| format!("Failed to clear cache at: {}", root.user_display()))?
60	    } else {
61	        let reporter = CleaningPackageReporter::new(printer, Some(packages.len()));
62	        let mut summary = Removal::default();
63	
64	        for package in packages {
65	            let removed = cache.remove(package)?;
66	            summary += removed;
67	            reporter.on_clean(package.as_str(), &summary);
68	        }
69	        reporter.on_complete();
70	
71	        summary
72	    };
73	
74	    // Write a summary of the number of files and directories removed.
75	    match (summary.num_files, summary.num_dirs) {
76	        (0, 0) => {
77	            write!(printer.stderr(), "No cache entries found")?;
78	        }
79	        (0, 1) => {
80	            write!(printer.stderr(), "Removed 1 directory")?;
81	        }
82	        (0, num_dirs_removed) => {
83	            write!(printer.stderr(), "Removed {num_dirs_removed} directories")?;
84	        }
85	        (1, _) => {
86	            write!(printer.stderr(), "Removed 1 file")?;
87	        }
88	        (num_files_removed, _) => {
89	            write!(printer.stderr(), "Removed {num_files_removed} files")?;
90	        }
91	    }
92	
93	    // If any, write a summary of the total byte count removed.
94	    if summary.total_bytes > 0 {
95	        let bytes = if summary.total_bytes < 1024 {
96	            format!("{}B", summary.total_bytes)
97	        } else {
98	            let (bytes, unit) = human_readable_bytes(summary.total_bytes);
99	            format!("{bytes:.1}{unit}")
100	        };
101	        write!(printer.stderr(), " ({})", bytes.green())?;
102	    }
103	
104	    writeln!(printer.stderr())?;
105	
106	    Ok(ExitStatus::Success)
107	}
