199	/// If the file is readonly, change the permissions to make it _not_ readonly.
200	fn set_not_readonly(path: &Path) -> io::Result<bool> {
201	    let mut perms = fs_err::metadata(path)?.permissions();
202	    if !perms.readonly() {
203	        return Ok(false);
