    #[arg(long, conflicts_with_all = ["locked", "upgrade", "no_sources"])]
    pub frozen: bool,

    /// Run the given path as a Python script.
    ///
    /// Using `--script` will attempt to parse the path as a PEP 723 script,
    /// irrespective of its extension.
