/// Add extra filtering for cache stats output (per-bucket table rows and total line).
#[must_use]
pub fn with_filtered_cache_stats(mut self) -> Self {
    // Filter the numeric size at the end of each table row (raw bytes or human-readable).
    // Matches lines like "wheels-v6               1234567" or "wheels-v6          1.2GiB".
    self.filters.push((
        r"(?m)(\s+)\d+(\.\d+)?[KMGT]?i?B?$".to_string(),
        "${1}[SIZE]".to_string(),
    ));
    self
}

