/// Add extra filtering for cache stats output (per-bucket table rows and total line).
///
/// Replaces each output line of the form `"<name>   <size>"` with `"<name> [SIZE]"` so that
/// snapshot tests are independent of the actual cache sizes on disk.
#[must_use]
pub fn with_filtered_cache_stats(mut self) -> Self {
    // Match each table row: non-whitespace name, whitespace padding, then a raw byte count
    // or human-readable size (e.g., `1.2GiB`).
    self.filters.push((
        r"(?m)^(\S+)\s+\d+(\.\d+)?[KMGT]?i?B?$".to_string(),
        "$1 [SIZE]".to_string(),
    ));
    self
}

