use std::fmt::Write;

use anyhow::Result;
use diskus::DiskUsage;
use uv_cache::{Cache, CacheBucket};
use uv_preview::{Preview, PreviewFeature};
use uv_warnings::warn_user;

use crate::commands::{ExitStatus, human_readable_bytes};
use crate::printer::Printer;

/// All cache buckets, including [`CacheBucket::Python`] which is absent from
/// [`CacheBucket::iter()`].
const ALL_BUCKETS: &[CacheBucket] = &[
    CacheBucket::Wheels,
    CacheBucket::SourceDistributions,
    CacheBucket::FlatIndex,
    CacheBucket::Git,
    CacheBucket::Interpreter,
    CacheBucket::Simple,
    CacheBucket::Archive,
    CacheBucket::Builds,
    CacheBucket::Environments,
    CacheBucket::Python,
    CacheBucket::Binaries,
];

/// Display per-bucket cache usage statistics.
pub(crate) fn cache_stats(
    cache: &Cache,
    human_readable: bool,
    printer: Printer,
    preview: Preview,
) -> Result<ExitStatus> {
    if !preview.is_enabled(PreviewFeature::CacheSize) {
        warn_user!(
            "`uv cache stats` is experimental and may change without warning. Pass \
             `--preview-features {}` to disable this warning.",
            PreviewFeature::CacheSize
        );
    }

    let format_size = |bytes: u64| -> String {
        if human_readable {
            let (amount, unit) = human_readable_bytes(bytes);
            format!("{amount:.1}{unit}")
        } else {
            format!("{bytes}")
        }
    };

    if !cache.root().exists() {
        for bucket in ALL_BUCKETS {
            writeln!(
                printer.stdout_important(),
                "{:<20} {:>12}",
                format!("{bucket}"),
                format_size(0),
            )?;
        }
        writeln!(
            printer.stdout_important(),
            "{:<20} {:>12}",
            "Total",
            format_size(0),
        )?;
        return Ok(ExitStatus::Success);
    }

    let mut total_bytes: u64 = 0;

    for bucket in ALL_BUCKETS {
        let path = cache.bucket(*bucket);
        let bytes = if path.exists() {
            DiskUsage::new(vec![path]).count_ignoring_errors()
        } else {
            0
        };
        total_bytes += bytes;

        writeln!(
            printer.stdout_important(),
            "{:<20} {:>12}",
            format!("{bucket}"),
            format_size(bytes),
        )?;
    }

    writeln!(
        printer.stdout_important(),
        "{:<20} {:>12}",
        "Total",
        format_size(total_bytes),
    )?;

    Ok(ExitStatus::Success)
}

    /// Show the cache size.
    ///
    /// Displays the total size of the cache directory. This includes all downloaded and built
    /// wheels, source distributions, and other cached data. By default, outputs the size in raw
    /// bytes; use `--human` for human-readable output.
    Size(SizeArgs),
    /// Show per-bucket cache usage statistics.
    ///
    /// Displays the size of each cache bucket (wheels, source distributions, git, etc.)
    /// alongside a total. By default, outputs sizes in raw bytes; use `--human` for
    /// human-readable output (e.g., `1.2 GiB`).
    Stats(StatsArgs),
}

#[derive(Args, Debug)]
pub struct CleanArgs {
    /// The packages to remove from the cache.
    #[arg(value_hint = ValueHint::Other)]
    pub package: Vec<PackageName>,

    /// Force removal of the cache, ignoring in-use checks.
    ///
    /// By default, `uv cache clean` will block until no process is reading the cache. When
    /// `--force` is used, `uv cache clean` will proceed without taking a lock.
    #[arg(long)]
    pub force: bool,
}

#[derive(Args, Debug)]
pub struct PruneArgs {
    /// Optimize the cache for persistence in a continuous integration environment, like GitHub
    /// Actions.
    ///
    /// By default, uv caches both the wheels that it builds from source and the pre-built wheels
    /// that it downloads directly, to enable high-performance package installation. In some
    /// scenarios, though, persisting pre-built wheels may be undesirable. For example, in GitHub
    /// Actions, it's faster to omit pre-built wheels from the cache and instead have re-download
    /// them on each run. However, it typically _is_ faster to cache wheels that are built from
    /// source, since the wheel building process can be expensive, especially for extension
    /// modules.
    ///
    /// In `--ci` mode, uv will prune any pre-built wheels from the cache, but retain any wheels
    /// that were built from source.
    #[arg(long)]
    pub ci: bool,

    /// Force removal of the cache, ignoring in-use checks.
    ///
    /// By default, `uv cache prune` will block until no process is reading the cache. When
    /// `--force` is used, `uv cache prune` will proceed without taking a lock.
    #[arg(long)]
    pub force: bool,
}

#[derive(Args, Debug)]
pub struct SizeArgs {
